package com.google.gson.examples.android.model;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import java.util.List;
import java.util.ArrayList;
import java.lang.reflect.Constructor;

class CartTest {

  @Test
  void testGetLineItems_returnsLineItemsList() throws Exception {
    List<LineItem> items = new ArrayList<>();
    items.add(new LineItem("item1", 2));
    items.add(new LineItem("item2", 5));

    // Use reflection to instantiate Cart since Cart class is not imported
    Class<?> cartClass = Class.forName("com.google.gson.examples.android.model.Cart");
    Constructor<?> constructor = cartClass.getConstructor(List.class, String.class, String.class);
    Object cart = constructor.newInstance(items, "buyerName", "1234-5678-9012-3456");

    // Invoke getLineItems method via reflection
    @SuppressWarnings("unchecked")
    List<Object> result = (List<Object>) cartClass.getMethod("getLineItems").invoke(cart);

    assertNotNull(result);
    assertEquals(2, result.size());

    // Access LineItem fields via reflection
    Class<?> lineItemClass = LineItem.class;

    Object item0 = result.get(0);
    Object item1 = result.get(1);

    assertEquals("item1", lineItemClass.getMethod("getName").invoke(item0));
    assertEquals(2, lineItemClass.getMethod("getQuantity").invoke(item0));
    assertEquals("item2", lineItemClass.getMethod("getName").invoke(item1));
    assertEquals(5, lineItemClass.getMethod("getQuantity").invoke(item1));
  }

  // Minimal LineItem class for testing
  static class LineItem {
    private final String name;
    private final int quantity;

    LineItem(String name, int quantity) {
      this.name = name;
      this.quantity = quantity;
    }

    String getName() {
      return name;
    }

    int getQuantity() {
      return quantity;
    }
  }
}
